--
-- Table structure for table `reservations`
--

DROP TABLE IF EXISTS `reservations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `reservations` (
  `id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `device_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `device_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `device_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reserver_id` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `reserver_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `start_time` datetime NOT NULL,
  `end_time` datetime NOT NULL,
  `status` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `custodian_approved` tinyint DEFAULT '0',
  `custodian_approved_at` datetime DEFAULT NULL,
  `borrower_approved` tinyint DEFAULT '0',
  `borrower_approved_at` datetime DEFAULT NULL,
  `custodian_notified` tinyint DEFAULT '0',
  `borrower_notified` tinyint DEFAULT '0',
  `cancelled_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cancelled_at` datetime DEFAULT NULL,
  `cancel_reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `rejected_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `rejected_at` datetime DEFAULT NULL,
  `converted_to_borrow` tinyint DEFAULT '0',
  `converted_at` datetime DEFAULT NULL,
  `custodian_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_borrower_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_borrower_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reason` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_device` (`device_id`,`device_type`),
  KEY `idx_reserver` (`reserver_id`),
  KEY `idx_status` (`status`),
  KEY `idx_time` (`start_time`,`end_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

